import { CalcAUD } from "../src/main.ts";

Deno.test("Issue Reproduction: Nested CalcAUD in from() should group", () => {
    // Current behavior according to user: results in "3 x 2^2 = 36"
    // Which is ambiguous because 3 x (2^2) = 12, but (3 x 2)^2 = 36
    const inner = CalcAUD.from(3).mult(2);
    const result = CalcAUD.from(inner).pow(2).commit(0);

    console.log("LaTeX:", result.toLaTeX());
    console.log("Unicode:", result.toUnicode());
    console.log("Verbal:", result.toVerbalA11y());
    console.log("Value:", result.toString());

    // Based on user report, it currently is "3 \times 2^{2} = 36" (LaTeX)
    // The user wants it to be "(3 \times 2)^{2} = 36"
});

Deno.test("Proposed behavior: from(CalcAUD) should automatically group", () => {
    const inner = CalcAUD.from(3).mult(2);
    const result = CalcAUD.from(inner).pow(2).commit(0);

    // If it automatically groups, it should be equivalent to:
    const expected = CalcAUD.from(3).mult(2).group().pow(2).commit(0);

    // assertEquals(result.toLaTeX(), expected.toLaTeX());
});

