Deno.test("Proposed behavior: from(CalcAUD) should automatically group", () => {
    const inner = CalcAUD.from(3).mult(2);
    const result = CalcAUD.from(inner).pow(2).commit(0);

    // If it automatically groups, it should be equivalent to:
    const expected = CalcAUD.from(3).mult(2).group().pow(2).commit(0);

    assertEquals(result.toLaTeX(), expected.toLaTeX());
    assertEquals(result.toString(), "36");
});

Deno.test("Proposed behavior: add(CalcAUD) should automatically group", () => {
    const inner = CalcAUD.from(3).mult(2);
    const result = CalcAUD.from(10).add(inner).commit(0);

    console.log("add(inner) LaTeX:", result.toLaTeX());
    // Should be 10 + (3 x 2) = 16
    assertEquals(result.toString(), "16");
    assertEquals(result.toLaTeX().includes("\\left( 3 \\times 2 \\right)"), true);
});

Deno.test("Proposed behavior: mult(CalcAUD) should automatically group", () => {
    const inner = CalcAUD.from(3).add(2);
    const result = CalcAUD.from(10).mult(inner).commit(0);

    console.log("mult(inner) LaTeX:", result.toLaTeX());
    // Should be 10 x (3 + 2) = 50
    assertEquals(result.toString(), "50");
    assertEquals(result.toLaTeX().includes("\\left( 3 + 2 \\right)"), true);
});

