            const parts = expStr.split("/");

            if (parts.length !== 2) {
                throw new CalcAUDError({
                    type: "invalid-fractional-exponent",
                    title: "Expoente Fracionário Inválido",
                    detail: `O expoente '${expStr}' deve conter apenas um numerador e um denominador.`,
                    operation: "pow",
