    const num = this.activeTermProductUnicode || "1";
    switch (this.activePendingOperation) {
        case "DIV":
            return `${wrapUnicode(num)} ÷ ${wrapUnicode(this.activeFactorUnicode)}`;
        case "DIV_INT":
            return `⌊${wrapUnicode(num)} ÷ ${wrapUnicode(this.activeFactorUnicode)}⌋`;
        case "MOD":
            return `${wrapUnicode(num)} mod ${wrapUnicode(this.activeFactorUnicode)}`;
        case "MULT":
