        const other = CalcAUD.from(value);
        const otherValue = other.accumulatedValue + other.getActiveTermValue();
        if (otherValue === 0n) {
            throw new CalcAUDError({
                type: "division-by-zero",
                title: "Operação Matemática Inválida",
                detail: "Tentativa de divisão inteira por zero.",
                operation: "divInt",
                latex: `\\lfloor \\frac{${this.getActiveTermLaTeX()}}{0} \\rfloor`,
                unicode: `⌊${this.getActiveTermUnicode()} ÷ 0⌋`,
            });
        }

        const currentActiveValue = this.getActiveTermValue();
        const currentActiveExpr = this.getActiveTermLaTeX();
        const currentActiveUnicode = this.getActiveTermUnicode();
        const currentActiveVerbal = this.getActiveTermVerbal();

        let quotient: bigint;
        let nextActiveExpr: string;
        let nextActiveUnicode: string;
        let nextActiveVerbal: string;

        if (divStrategy === "euclidean") {
            // Lógica Euclidiana: O quociente é o piso (floor) da divisão real
            quotient = currentActiveValue / otherValue;
            const remainder = currentActiveValue % otherValue;

            if (remainder !== 0n && ((currentActiveValue < 0n) !== (otherValue < 0n))) {
                quotient -= 1n;
            }
            nextActiveExpr = `\\lfloor \\frac{${currentActiveExpr}}{${other.getFullLaTeXExpression()}} \\rfloor`;
            nextActiveUnicode = `⌊${currentActiveUnicode} ÷ ${other.getFullUnicodeExpression()}⌋`;
            nextActiveVerbal = `${currentActiveVerbal}${VERBAL_TOKENS.DIV_INT_E_MID}${other.getFullVerbalExpression()}${VERBAL_TOKENS.DIV_INT_E_SUF}`;
