            // Lógica Truncada: Descarta a parte fracionária (padrão C/Java/JS)
            quotient = currentActiveValue / otherValue;
            nextActiveExpr = `\\operatorname{trunc}\\left(\\frac{${currentActiveExpr}}{${other.getFullLaTeXExpression()}}\\right)`;
            nextActiveUnicode = `trun(${currentActiveUnicode} ÷ ${other.getFullUnicodeExpression()})`;
            nextActiveVerbal = `${currentActiveVerbal}${VERBAL_TOKENS.DIV_INT_T_MID}${other.getFullVerbalExpression()}${VERBAL_TOKENS.DIV_INT_T_SUF}`;
