        const nextActiveValue = quotient * INTERNAL_SCALE_FACTOR;

        const result = new CalcAUD(
            this.accumulatedValue,
            INTERNAL_SCALE_FACTOR,
            nextActiveValue,
            false,
            this.accumulatedExpression,
